import scala.xml._
import scala.util.{Try, Success, Failure}
import java.io.StringReader
import javax.xml.parsers.SAXParserFactory
import org.xml.sax.InputSource

case class ConfigurationSettings(
  settings: Map[String, String],
  nested: Map[String, ConfigurationSettings] = Map.empty
)

class ConfigurationParserService {
  
  private val secureParserFactory: SAXParserFactory = {
    val factory = SAXParserFactory.newInstance()
    factory.setFeature("http://xml.org/sax/features/external-general-entities", false)
    factory.setFeature("http://xml.org/sax/features/external-parameter-entities", false)
    factory.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true)
    factory.setFeature("http://apache.org/xml/features/nonvalidating/load-external-dtd", false)
    factory.setXIncludeAware(false)
    factory.setNamespaceAware(true)
    factory
  }

  def parseConfiguration(xmlContent: String): Try[ConfigurationSettings] = {
    Try {
      val loader = new scala.xml.factory.XMLLoader[Elem] {
        override def parser = secureParserFactory.newSAXParser()
      }
      val xml = loader.load(new InputSource(new StringReader(xmlContent)))
      extractSettings(xml)
    }
  }

  def parseConfigurationUnsafe(xmlContent: String): Try[ConfigurationSettings] = {
    Try {
      val xml = XML.loadString(xmlContent)
      extractSettings(xml)
    }
  }

  private def extractSettings(elem: Elem): ConfigurationSettings = {
    val directSettings = elem.child.collect {
      case e: Elem if e.child.forall(_.isInstanceOf[Text]) =>
        e.label -> e.text.trim
    }.toMap

    val nestedConfigs = elem.child.collect {
      case e: Elem if e.child.exists(_.isInstanceOf[Elem]) =>
        e.label -> extractSettings(e)
    }.toMap

    ConfigurationSettings(directSettings, nestedConfigs)
  }

  def getSettingValue(config: ConfigurationSettings, path: String): Option[String] = {
    val parts = path.split('.')
    parts.toList match {
      case single :: Nil => config.settings.get(single)
      case head :: tail =>
        config.nested.get(head).flatMap(nested => getSettingValue(nested, tail.mkString(".")))
      case Nil => None
    }
  }

  def getAllSettings(config: ConfigurationSettings, prefix: String = ""): Map[String, String] = {
    val direct = config.settings.map { case (k, v) =>
      if (prefix.isEmpty) k -> v else s"$prefix.$k" -> v
    }

    val nested = config.nested.flatMap { case (k, v) =>
      val newPrefix = if (prefix.isEmpty) k else s"$prefix.$k"
      getAllSettings(v, newPrefix)
    }

    direct ++ nested
  }

  def mergeConfigurations(configs: ConfigurationSettings*): ConfigurationSettings = {
    configs.reduce { (acc, config) =>
      ConfigurationSettings(
        acc.settings ++ config.settings,
        acc.nested ++ config.nested.map { case (k, v) =>
          k -> acc.nested.get(k).map(existing => mergeConfigurations(existing, v)).getOrElse(v)
        }
      )
    }
  }

  def validateConfiguration(config: ConfigurationSettings, requiredKeys: Set[String]): Either[List[String], Unit] = {
    val allKeys = getAllSettings(config).keySet
    val missing = requiredKeys.diff(allKeys)
    if (missing.isEmpty) Right(())
    else Left(missing.toList)
  }
}

trait ConfigurationAPI {
  val parserService: ConfigurationParserService

  def handleConfigurationRequest(xmlContent: String, secure: Boolean = true): Either[String, ConfigurationSettings] = {
    val parseResult = if (secure) {
      parserService.parseConfiguration(xmlContent)
    } else {
      parserService.parseConfigurationUnsafe(xmlContent)
    }

    parseResult match {
      case Success(config) => Right(config)
      case Failure(ex) => Left(s"Failed to parse configuration: ${ex.getMessage}")
    }
  }

  def handleGetSetting(xmlContent: String, path: String, secure: Boolean = true): Either[String, String] = {
    handleConfigurationRequest(xmlContent, secure).flatMap { config =>
      parserService.getSettingValue(config, path)
        .toRight(s"Setting not found at path: $path")
    }
  }

  def handleGetAllSettings(xmlContent: String, secure: Boolean = true): Either[String, Map[String, String]] = {
    handleConfigurationRequest(xmlContent, secure).map { config =>
      parserService.getAllSettings(config)
    }
  }

  def handleMergeConfigurations(xmlContents: List[String], secure: Boolean = true): Either[String, ConfigurationSettings] = {
    val parsed = xmlContents.map(xml => handleConfigurationRequest(xml, secure))
    val errors = parsed.collect { case Left(err) => err }
    
    if (errors.nonEmpty) {
      Left(s"Failed to parse configurations: ${errors.mkString(", ")}")
    } else {
      val configs = parsed.collect { case Right(config) => config }
      Right(parserService.mergeConfigurations(configs: _*))
    }
  }

  def handleValidateConfiguration(
    xmlContent: String,
    requiredKeys: Set[String],
    secure: Boolean = true
  ): Either[String, Unit] = {
    handleConfigurationRequest(xmlContent, secure).flatMap { config =>
      parserService.validateConfiguration(config, requiredKeys) match {
        case Right(_) => Right(())
        case Left(missing) => Left(s"Missing required keys: ${missing.mkString(", ")}")
      }
    }
  }
}

class ConfigurationManagementService extends ConfigurationAPI {
  override val parserService: ConfigurationParserService = new ConfigurationParserService()

  def processConfigurationFromAPI(
    xmlContent: String,
    operation: String = "parse",
    params: Map[String, Any] = Map.empty
  ): Either[String, Any] = {
    operation match {
      case "parse" =>
        val secure = params.getOrElse("secure", true).asInstanceOf[Boolean]
        handleConfigurationRequest(xmlContent, secure)

      case "get" =>
        val path = params.getOrElse("path", "").asInstanceOf[String]
        val secure = params.getOrElse("secure", true).asInstanceOf[Boolean]
        if (path.isEmpty) Left("Path parameter is required")
        else handleGetSetting(xmlContent, path, secure)

      case "getAll" =>
        val secure = params.getOrElse("secure", true).asInstanceOf[Boolean]
        handleGetAllSettings(xmlContent, secure)

      case "validate" =>
        val requiredKeys = params.getOrElse("requiredKeys", Set.empty[String]).asInstanceOf[Set[String]]
        val secure = params.getOrElse("secure", true).asInstanceOf[Boolean]
        handleValidateConfiguration(xmlContent, requiredKeys, secure)

      case _ =>
        Left(s"Unknown operation: $operation")
    }
  }

  def processBatchConfiguration(
    xmlContents: List[String],
    operation: String = "merge"
  ): Either[String, ConfigurationSettings] = {
    operation match {
      case "merge" =>
        handleMergeConfigurations(xmlContents, secure = true)
      case _ =>
        Left(s"Unknown batch operation: $operation")
    }
  }
}

object ConfigurationManagementApp {
  def main(args: Array[String]): Unit = {
    val service = new ConfigurationManagementService()

    val sampleXml = """<?xml version="1.0" encoding="UTF-8"?>
      <configuration>
        <database>
          <host>localhost</host>
          <port>5432</port>
          <name>mydb</name>
        </database>
        <server>
          <host>0.0.0.0</host>
          <port>8080</port>
        </server>
        <timeout>30</timeout>
      </configuration>"""

    service.processConfigurationFromAPI(sampleXml, "parse") match {
      case Right(config: ConfigurationSettings) =>
        println("Configuration parsed successfully")
        println(s"All settings: ${service.parserService.getAllSettings(config)}")
      case Left(error) =>
        println(s"Error: $error")
      case _ =>
        println("Unexpected result")
    }

    service.processConfigurationFromAPI(
      sampleXml,
      "get",
      Map("path" -> "database.host")
    ) match {
      case Right(value) => println(s"Database host: $value")
      case Left(error) => println(s"Error: $error")
    }
  }
}